try {
  if (!app?.profileId) {
    return {
      data: {
        uuid: data?.data?.uuid || "",
        title: data?.data?.title || "",
        description: data?.data?.description || "",
        version: data?.data?.version || "",
        controls: [
          {
            code: "Select a profile",
            title: "",
            description: "",
            tags: []
          }
        ]
      }
    };
  }

  var selectedTags = widget['e86ecbd8-7c2f-4faa-a090-a2f9712a7a9d']?.value;

  if (!selectedTags || selectedTags.length === 0) {
    return data;
  }

  var filteredControls = [];
  var includeNoTags = false;

  for (var k = 0; k < selectedTags.length; k++) {
    if (selectedTags[k] === 'No tags') {
      includeNoTags = true;
      break;
    }
  }

  var controls = Array.isArray(data?.data?.controls) ? data.data.controls : [];

  for (var i = 0; i < controls.length; i++) {
    var control = controls[i] || {};
    var codePrefix = String(control.code || "").split('-')[0];

    var matches = false;

    var hasValidTags = false;
    if (control.tags && control.tags.length > 0) {
      for (var t = 0; t < control.tags.length; t++) {
        if (control.tags[t] && String(control.tags[t]).trim() !== '') {
          hasValidTags = true;
          break;
        }
      }
    }

    if (!hasValidTags && includeNoTags) {
      matches = true;
    } else if (hasValidTags) {
      for (var j = 0; j < selectedTags.length; j++) {
        if (selectedTags[j] !== 'No tags' && codePrefix === selectedTags[j]) {
          matches = true;
          break;
        }
      }
    }

    if (matches) {
      filteredControls.push(control);
    }
  }

  return {
    data: {
      uuid: data?.data?.uuid || "",
      title: data?.data?.title || "",
      description: data?.data?.description || "",
      version: data?.data?.version || "",
      controls: filteredControls
    }
  };
} catch (error) {
  return data;
}

